        return isBoomerangHelper(x1, y1, x2, y2, x3, y3, 0, 0) && isBoomerangHelper(x1, y1, x2, y2, x3, y3, 1, 0) && isBoomerangHelper(x1, y1, x2, y2, x3, y3, 0, 1);
    }

    public boolean isBoomerangHelper(int x1, int y1, int x2, int y2, int x3, int y3, int direction, int count) {
